<template><div class="page-content"><PageHeader eyebrow="Pipeline run" :title="name" description="Tekton 任务执行链路与实时日志"><el-button :loading="loading" @click="refresh">刷新</el-button><el-button type="primary" :disabled="details?.status!=='Failed'" @click="analyze">✦ AI 分析失败</el-button></PageHeader><el-skeleton :loading="loading&&!details" animated :rows="9"><template v-if="details"><section class="summary surface"><div><span>Status</span><StatusBadge :status="details.status"/></div><div><span>Started</span><b>{{format(details.started_at)}}</b></div><div><span>Finished</span><b>{{format(details.finished_at)}}</b></div><div><span>Duration</span><b>{{duration}}</b></div><div class="reason"><span>Reason</span><b>{{details.message||details.reason}}</b></div></section><section class="surface flow"><div class="surface-header"><div><h3>Task execution flow</h3><p>点击 Task 查看对应 Step 日志</p></div><span>{{details.tasks.length}} tasks</span></div><PipelineStatusTimeline :tasks="details.tasks" :selected="selectedTask?.name" @select="selectedTask=$event"/></section><div class="content-grid"><aside class="surface tasks"><div class="surface-header"><div><h3>Task runs</h3><p>执行状态</p></div></div><button v-for="task in details.tasks" :key="task.name" :class="{active:selectedTask?.name===task.name,failed:task.status==='Failed'}" @click="selectedTask=task"><i/><div><b>{{task.task_name||task.name}}</b><small>{{task.pod||'Pod pending'}}</small></div><StatusBadge :status="task.status"/></button></aside><TaskRunLogViewer :task="selectedTask" @analyze="analyze"/></div></template><EmptyState v-else title="PipelineRun 不可用" description="无法读取该流水线，可能已被清理或后端连接异常。"/></el-skeleton></div></template>
<script setup lang="ts">import{computed,onBeforeUnmount,onMounted,ref}from'vue';import{useRoute}from'vue-router';import{ElMessage}from'element-plus';import{pipelineApi}from'../api/pipeline';import PageHeader from'../components/common/PageHeader.vue';import StatusBadge from'../components/common/StatusBadge.vue';import EmptyState from'../components/common/EmptyState.vue';import PipelineStatusTimeline from'../components/pipeline/PipelineStatusTimeline.vue';import TaskRunLogViewer from'../components/pipeline/TaskRunLogViewer.vue';const name=String(useRoute().params.name),details=ref<Awaited<ReturnType<typeof pipelineApi.logs>>>(),selectedTask=ref<any>(),loading=ref(false);let timer:number|undefined;const format=(v?:string)=>v?new Date(v).toLocaleString('zh-CN',{hour12:false}):'—';const duration=computed(()=>details.value?.started_at&&details.value?.finished_at?`${Math.round((new Date(details.value.finished_at).getTime()-new Date(details.value.started_at).getTime())/1000)}s`:'Running');async function refresh(){loading.value=true;try{details.value=await pipelineApi.logs(name);selectedTask.value=details.value.tasks.find(t=>t.name===selectedTask.value?.name)||details.value.tasks.find(t=>t.status==='Failed')||details.value.tasks[0];if(['Succeeded','Failed'].includes(details.value.status))clearInterval(timer)}catch(e){ElMessage.error((e as Error).message)}finally{loading.value=false}}function analyze(){ElMessage.info('AI 失败分析将在下一阶段接入模型服务')}onMounted(async()=>{await refresh();timer=window.setInterval(refresh,5000)});onBeforeUnmount(()=>clearInterval(timer))

</script>
<style scoped>.summary{min-height:67px;padding:13px 17px;display:grid;grid-template-columns:120px 180px 180px 100px 1fr;align-items:center;margin-bottom:14px;box-shadow:none}.summary>div{padding:0 15px;border-right:1px solid var(--border-soft)}.summary>div:first-child{padding-left:0}.summary>div:last-child{border:0}.summary span,.summary b{display:block}.summary>div>span{font-size:12px;color:var(--muted);margin-bottom:6px}.summary b{font-size:13px;font-weight:500;color:var(--text-2)}.summary .reason b{white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.flow{margin-bottom:14px;overflow:hidden}.surface-header>span{font-size:12px;color:var(--muted)}.content-grid{display:grid;grid-template-columns:270px 1fr;gap:14px}.tasks{overflow:hidden}.tasks>button{width:100%;min-height:61px;padding:0 13px;border:0;border-bottom:1px solid var(--border-soft);background:none;color:var(--text-2);display:flex;align-items:center;gap:9px;text-align:left}.tasks>button:hover,.tasks>button.active{background:#161a23}.tasks>button.active{box-shadow:inset 2px 0 var(--primary)}.tasks>button>i{width:6px;height:6px;border-radius:50%;background:var(--success)}.tasks>button.failed>i{background:var(--danger)}.tasks>button>div{flex:1;min-width:0}.tasks>button b,.tasks>button small{display:block}.tasks>button b{font-size:13px}.tasks>button small{font-size:13px;color:var(--subtle);margin-top:5px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}@media(max-width:1050px){.summary{grid-template-columns:1fr 1fr}.summary .reason{display:none}.content-grid{grid-template-columns:1fr}}</style>
